document.addEventListener("DOMContentLoaded",function(){const e=document.getElementById("article-select");e&&e.addEventListener("change",function(){const e=this.value;if(document.querySelectorAll(".highlight").forEach(e=>{e.classList.remove("highlight")}),e){const t=document.querySelector(e);t&&(t.scrollIntoView({behavior:"smooth",block:"center"}),setTimeout(()=>{t.classList.add("highlight")},500))}})});